import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { FaShareSquare, FaPencilAlt, FaHeart, FaPlay } from 'react-icons/fa';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { usePlayer } from '../context/PlayerContext';

const Profile = () => {
  const { user, updateUser } = useAuth();
  const { playSong } = usePlayer();
  const [uploading, setUploading] = useState(false);
  const [profileData, setProfileData] = useState(null);
  const [mySongs, setMySongs] = useState([]); 
  const [activeTab, setActiveTab] = useState('all');
  
  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState("");

  useEffect(() => {
    const fetchUserData = async () => {
        if (user) {
            try {
                const res = await axios.get(`http://localhost:5000/api/users/${user._id}`);
                setProfileData(res.data);

                const resSongs = await axios.get(`http://localhost:5000/api/songs?uploader=${user._id}`);
                setMySongs(resSongs.data);
            } catch (err) {
                console.error(err);
            }
        }
    };
    fetchUserData();
  }, [user]);

  useEffect(() => {
    if (user) setEditName(user.username);
  }, [user]);

  const handleAvatarChange = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('avatar', file);

    setUploading(true);
    try {
      const res = await axios.put(`http://localhost:5000/api/users/${user._id}`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
          'token': `Bearer ${user.token}`
        }
      });
      updateUser(res.data);
      setUploading(false);
    } catch (err) {
      console.error(err);
      setUploading(false);
      alert("Update failed!");
    }
  };

  const handleSaveName = async () => {
      if (!editName.trim()) return alert("Tên không được để trống");
      try {
          const formData = new FormData();
          formData.append('username', editName);

          const res = await axios.put(`http://localhost:5000/api/users/${user._id}`, formData, {
              headers: { 
                  'Content-Type': 'multipart/form-data',
                  'token': `Bearer ${user.token}` 
              }
          });
          updateUser(res.data);
          setIsEditing(false);
      } catch (err) {
          console.error(err);
          alert("Cập nhật thất bại! Tên có thể đã tồn tại.");
      }
  };

  const renderSongList = (songs, title) => (
    <div className="mb-8 animate-fade-in-up">
        <h3 className="font-bold text-gray-600 mb-3 border-b border-gray-200 pb-2 text-lg">{title}</h3>
        {songs && songs.length > 0 ? (
            <div className="grid grid-cols-1 gap-2">
                {songs.map(song => (
                    <div key={song._id} className="flex items-center gap-4 p-3 hover:bg-white hover:shadow-sm rounded-xl group cursor-pointer transition border border-transparent hover:border-[#A5D8FF]/30" onClick={() => playSong(song)}>
                        <div className="relative w-12 h-12 flex-shrink-0">
                            <img src={song.coverImage} alt="cover" className="w-full h-full object-cover rounded-lg" />
                            <div className="absolute inset-0 bg-[#A5D8FF]/20 hidden group-hover:flex items-center justify-center text-white rounded-lg">
                                <FaPlay size={14} className="text-[#FFB703]" />
                            </div>
                        </div>
                        <div className="overflow-hidden flex-1">
                            <p className="text-sm font-bold truncate text-gray-700 group-hover:text-[#FFB703]">{song.title}</p>
                            <p className="text-xs text-gray-400 truncate">{song.artist}</p>
                        </div>
                        <div className="text-xs text-gray-400 flex items-center gap-1">
                            <FaHeart /> {song.likes}
                        </div>
                    </div>
                ))}
            </div>
        ) : (
            <p className="text-sm text-gray-400 italic py-4">No tracks found.</p>
        )}
    </div>
  );

  const renderTabContent = () => {
      switch (activeTab) {
          case 'popular':
              const popularSongs = [...mySongs].sort((a, b) => b.plays - a.plays).slice(0, 5);
              return renderSongList(popularSongs, "Most Popular Tracks");
          case 'tracks':
              return renderSongList(mySongs, "All Uploaded Tracks");
          case 'albums':
              return (
                  <div className="text-center py-16 border-2 border-dashed border-[#A5D8FF]/30 rounded-xl bg-white">
                      <h3 className="text-lg font-bold text-gray-600 mb-2">No Albums yet</h3>
                      <p className="text-gray-400 text-sm">Create an album to organize your tracks.</p>
                  </div>
              );
          case 'all':
          default:
              return (
                  <>
                      {profileData && renderSongList(profileData.history, "Recently Played")}
                      {profileData && renderSongList(profileData.likedSongs, "Liked Tracks")}
                  </>
              );
      }
  };

  if (!user) return <div className="text-center mt-20">Please login to view profile.</div>;

  return (
    <div className="bg-[#FAF7F2] min-h-screen pb-24">
      {/* 1. Header Section */}
      <div className="relative h-80 w-full bg-gradient-to-r from-[#A5D8FF] to-[#FFB703]">
        <div className="max-w-7xl mx-auto px-8 h-full relative flex items-center">
            <div className="relative w-52 h-52 rounded-full border-4 border-white overflow-hidden shadow-xl group ml-4 bg-white">
                <img 
                    src={user.avatar || `https://ui-avatars.com/api/?name=${user.username}&background=random&size=200`} 
                    alt="avatar" 
                    className="w-full h-full object-cover"
                />
                <label className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white/90 text-gray-700 text-xs px-3 py-1.5 rounded-full cursor-pointer hover:bg-white transition opacity-0 group-hover:opacity-100 whitespace-nowrap shadow-sm font-bold">
                    {uploading ? 'Uploading...' : 'Upload image'}
                    <input type="file" className="hidden" onChange={handleAvatarChange} accept="image/*" />
                </label>
            </div>
            
            <div className="ml-6 flex flex-col gap-2">
                {isEditing ? (
                    <div className="flex flex-col gap-2 animate-fade-in-up">
                        <input 
                            type="text" 
                            value={editName}
                            onChange={(e) => setEditName(e.target.value)}
                            className="text-3xl font-bold text-white bg-white/20 backdrop-blur-md border border-white/50 rounded-lg px-3 py-1 focus:outline-none focus:border-white shadow-inner"
                            autoFocus
                        />
                        <div className="flex gap-2">
                            <button onClick={handleSaveName} className="bg-white text-[#FFB703] px-4 py-1 rounded-full text-sm font-bold hover:bg-gray-100 shadow-sm transition">Save</button>
                            <button onClick={() => { setIsEditing(false); setEditName(user.username); }} className="bg-black/20 text-white px-4 py-1 rounded-full text-sm hover:bg-black/30 transition">Cancel</button>
                        </div>
                    </div>
                ) : (
                    <>
                        <h2 className="text-3xl font-bold text-white drop-shadow-md px-3 py-1 inline-block w-fit">{user.username}</h2>
                        <p className="text-sm text-white/90 bg-black/10 backdrop-blur-sm px-3 py-1 rounded-full inline-block w-fit">{user.username}</p>
                    </>
                )}
            </div>
            
            <button className="absolute top-8 right-8 bg-white/20 backdrop-blur-md text-white px-4 py-2 rounded-full text-sm font-bold border border-white/40 hover:bg-white/30 transition">
                Upload header image
            </button>
        </div>
      </div>

      {/* 2. Navigation Tabs */}
      <div className="bg-white border-b border-gray-100 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 py-3 flex justify-between items-center h-16">
            <div className="flex gap-6 text-sm font-bold text-gray-400 ml-4">
                <button 
                    onClick={() => setActiveTab('all')}
                    className={`transition ${activeTab === 'all' ? 'text-[#FFB703] border-b-2 border-[#FFB703] pb-4 -mb-4' : 'hover:text-gray-600'}`}
                >
                    All
                </button>
                <button 
                    onClick={() => setActiveTab('popular')}
                    className={`transition ${activeTab === 'popular' ? 'text-[#FFB703] border-b-2 border-[#FFB703] pb-4 -mb-4' : 'hover:text-gray-600'}`}
                >
                    Popular tracks
                </button>
                <button 
                    onClick={() => setActiveTab('tracks')}
                    className={`transition ${activeTab === 'tracks' ? 'text-[#FFB703] border-b-2 border-[#FFB703] pb-4 -mb-4' : 'hover:text-gray-600'}`}
                >
                    Tracks
                </button>
                <button 
                    onClick={() => setActiveTab('albums')}
                    className={`transition ${activeTab === 'albums' ? 'text-[#FFB703] border-b-2 border-[#FFB703] pb-4 -mb-4' : 'hover:text-gray-600'}`}
                >
                    Albums
                </button>
            </div>
            <div className="flex gap-2">
                <button className="flex items-center gap-2 px-3 py-1 border border-gray-200 rounded-md text-sm text-gray-500 hover:border-[#A5D8FF] hover:text-[#A5D8FF] transition"><FaShareSquare /> Share</button>
                <button 
                    onClick={() => setIsEditing(true)}
                    className={`flex items-center gap-2 px-3 py-1 border border-gray-200 rounded-md text-sm transition ${isEditing ? 'bg-[#FFB703] text-white border-[#FFB703]' : 'text-gray-500 hover:border-[#A5D8FF] hover:text-[#A5D8FF]'}`}
                >
                    <FaPencilAlt /> Edit
                </button>
            </div>
        </div>
      </div>

      {/* 3. Main Content */}
      <div className="max-w-7xl mx-auto px-6 mt-8 grid grid-cols-1 lg:grid-cols-4 gap-8">
        <div className="lg:col-span-3">
            {renderTabContent()}
            {activeTab === 'all' && (!profileData?.history?.length && !profileData?.likedSongs?.length) && (
                <div className="text-center py-16 border-2 border-dashed border-[#A5D8FF]/30 rounded-xl bg-white">
                    <h3 className="text-lg font-bold text-gray-600 mb-2">Seems a little quiet over here</h3>
                    <p className="text-gray-400 text-sm mb-6">Start listening or upload a track.</p>
                    <Link to="/" className="bg-[#FFB703] text-white px-6 py-2 rounded-full font-bold hover:bg-orange-400 transition shadow-md">Explore Now</Link>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            <div className="flex justify-between text-gray-500 text-xs border-b pb-4">
                <div className="cursor-pointer hover:text-orange-500">
                    <div className="text-gray-400 uppercase mb-1">Tracks</div>
                    <div className="text-xl font-bold text-gray-700">{mySongs.length}</div>
                </div>
                <div className="cursor-pointer hover:text-orange-500">
                    <div className="text-gray-400 uppercase mb-1">Likes</div>
                    <div className="text-xl font-bold text-gray-700">{profileData?.likedSongs?.length || 0}</div>
                </div>
                <div className="cursor-pointer hover:text-orange-500">
                    <div className="text-gray-400 uppercase mb-1">History</div>
                    <div className="text-xl font-bold text-gray-700">{profileData?.history?.length || 0}</div>
                </div>
            </div>

            <div>
                <div className="flex justify-between items-end mb-3">
                    <span className="text-gray-500 text-xs font-bold uppercase flex items-center gap-1">
                        {profileData?.likedSongs?.length || 0} Likes <FaHeart className="text-gray-400" />
                    </span>
                </div>
                <div className="grid grid-cols-3 gap-2">
                    {profileData?.likedSongs?.slice(0, 9).map(song => (
                        <div key={song._id} className="aspect-square bg-gray-200 rounded overflow-hidden cursor-pointer hover:opacity-80 transition" title={song.title} onClick={() => playSong(song)}>
                            <img src={song.coverImage} alt="cover" className="w-full h-full object-cover" />
                        </div>
                    ))}
                </div>
            </div>
            
            <div className="text-[10px] text-gray-400 pt-4 border-t">
                Legal • Privacy • Cookies • Imprint • Creator Resources • Blog • Charts
            </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;
